import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

function Cart() {
  const [cartItems, setCartItems] = useState([]);

  useEffect(() => {
    const items = JSON.parse(localStorage.getItem('cart')) || [];
    setCartItems(items);
  }, []);

  const saveToLocalStorage = (newCartItems) => {
    setCartItems(newCartItems);
    localStorage.setItem('cart', JSON.stringify(newCartItems));
  }

  const clearCart = () => {
    saveToLocalStorage([]);
  };

  const removeProduct = (id) => {
    const updatedCart = cartItems.filter(item => item.id !== id);
    saveToLocalStorage(updatedCart);
  };

  const increaseQuantity = (product) => {
    const updatedCart = [...cartItems, product];
    saveToLocalStorage(updatedCart);
  };

  const decreaseQuantity = (id) => {
    const indexToRemove = cartItems.findIndex(item => item.id === id);
    if (indexToRemove !== -1) {
      const updatedCart = [...cartItems];
      updatedCart.splice(indexToRemove, 1);
      saveToLocalStorage(updatedCart);
    }
  };

  // Group items by ID for display
  const groupedCart = cartItems.reduce((acc, item) => {
    if (!acc[item.id]) {
      acc[item.id] = { ...item, quantity: 1 };
    } else {
      acc[item.id].quantity += 1;
    }
    return acc;
  }, {});

  const displayItems = Object.values(groupedCart);
  const total = cartItems.reduce((sum, item) => sum + item.price, 0);

  return (
    <div>
      <h2 className="text-center">Your Cart</h2>
      {cartItems.length === 0 ? (
        <div className="text-center">
          <p>Your cart is empty.</p>
          <Link to="/menu" className="btn mt-2">Browse Menu</Link>
        </div>
      ) : (
        <div style={{ maxWidth: '700px', margin: '0 auto', background: 'white', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
          <ul style={{ listStyle: 'none', padding: 0 }}>
            {displayItems.map((item) => (
              <li key={item.id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '15px 10px', borderBottom: '1px solid #eee' }}>
                <div style={{ flex: 1, display: 'flex', alignItems: 'center' }}>
                  <img src={item.image} alt={item.name} style={{ width: '50px', height: '50px', objectFit: 'cover', borderRadius: '4px', marginRight: '15px' }} />
                  <span style={{ fontWeight: 'bold' }}>{item.name}</span>
                </div>

                <div style={{ display: 'flex', gap: '15px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                    <button onClick={() => decreaseQuantity(item.id)} style={{ padding: '2px 8px', cursor: 'pointer', border: '1px solid #ccc', background: 'none' }}>-</button>
                    <span style={{ width: '20px', textAlign: 'center' }}>{item.quantity}</span>
                    <button onClick={() => increaseQuantity(item)} style={{ padding: '2px 8px', cursor: 'pointer', border: '1px solid #ccc', background: 'none' }}>+</button>
                  </div>
                  <div style={{ minWidth: '70px', textAlign: 'right', alignSelf: 'center' }}>
                    ${(item.price * item.quantity).toFixed(2)}
                  </div>
                  <button onClick={() => removeProduct(item.id)} style={{ color: '#E63946', border: 'none', background: 'none', cursor: 'pointer', alignSelf: 'center' }}>Remove</button>
                </div>
              </li>
            ))}
          </ul>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 'bold', fontSize: '1.4rem', marginTop: '1.5rem', paddingTop: '1rem', borderTop: '2px solid #ccc' }}>
            <span>Total:</span>
            <span>${total.toFixed(2)}</span>
          </div>
          <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
            <button className="btn" style={{ flex: 1 }} onClick={() => alert('Proceeding to checkout!... (Backend integration needed)')}>Checkout</button>
            <button className="btn" style={{ backgroundColor: '#f4f4f4', color: '#1D3557', border: '1px solid #1D3557' }} onClick={clearCart}>Clear Cart</button>
          </div>
        </div>
      )}
    </div>
  );
}

export default Cart;
